  1→/**
  2→ * Walking Skeleton: Intent Authorization Pipeline E2E
  3→ *
  4→ * Traces: US-1, US-2, US-4, US-5, US-6
  5→ *
  6→ * These are the minimum viable E2E paths through the intent authorization system.
  7→ * Skeleton 1: Agent declares intent -> evaluation -> auto-approve -> execution
  8→ * Skeleton 2: Agent declares intent -> evaluation -> veto window -> human vetoes
  9→ *
 10→ * Together they prove:
 11→ * - An agent can declare and submit an intent for authorization
 12→ * - The evaluation pipeline processes intents and routes by risk
 13→ * - Low-risk intents flow through to execution without human involvement
 14→ * - High-risk intents are surfaced to humans who can block execution
 15→ *
 16→ * Driving ports:
 17→ *   MCP tools: create_intent, submit_intent, get_intent_status
 18→ *   POST /api/workspaces/:ws/intents/:id/veto
 19→ *   POST /api/intents/:id/evaluate (SurrealQL EVENT target)
 20→ */
 21→import { describe, expect, it } from "bun:test";
 22→import { RecordId } from "surrealdb";
 23→import {
 24→  setupOrchestratorSuite,
 25→  createTestUser,
 26→  createTestWorkspace,
 27→  createReadyTask,
 28→  getTestUserBearerToken,
 29→  createDraftIntent,
 30→  submitIntent,
 31→  getIntentStatus,
 32→  getIntentRecord,
 33→  getIntentEvaluation,
 34→  waitForIntentStatus,
 35→  simulateEvaluation,
 36→  vetoIntent,
 37→  listPendingIntents,
 38→  createTestIdentity,
 39→} from "./intent-test-kit";
 40→
 41→const getRuntime = setupOrchestratorSuite("intent_walking_skeleton");
 42→
 43→describe("Walking Skeleton: Agent intent is authorized and proceeds to execution", () => {
 44→  // ---------------------------------------------------------------------------
 45→  // Walking Skeleton 1: Low-risk intent auto-approved
 46→  // US-1 + US-2 + US-5 + US-6 happy path
 47→  // ---------------------------------------------------------------------------
 48→  it("agent creates a low-risk intent, submits for authorization, and receives auto-approval", async () => {
 49→    const { baseUrl, surreal } = getRuntime();
 50→
 51→    // Given a workspace with a task ready for an agent to work on
 52→    const user = await createTestUser(baseUrl, "skeleton-approve");
 53→    const workspace = await createTestWorkspace(baseUrl, user);
 54→    const task = await createReadyTask(surreal, workspace.workspaceId, {
 55→      title: "Add input validation to signup form",
 56→      description: "Validate email format and password strength",
 57→    });
 58→
 59→    // And an agent identity that will request authorization
 60→    const agentIdentityId = await createTestIdentity(surreal, "coding-agent", "agent");
 61→
 62→    // When the agent creates an intent declaring what it wants to do
 63→    const { intentId } = await createDraftIntent(
 64→      surreal,
 65→      workspace.workspaceId,
 66→      agentIdentityId,
 67→      {
 68→        goal: "Add email format validation to the signup form",
 69→        reasoning: "The task requires input validation. Email validation is a safe, well-scoped change limited to the signup form component.",
 70→        priority: 50,
 71→        action_spec: {
 72→          provider: "file_editor",
 73→          action: "edit_file",
 74→          params: { target: "src/components/SignupForm.tsx" },
 75→        },
 76→        taskId: task.taskId,
 77→      },
 78→    );
 79→
 80→    // Then the intent is created in draft status
 81→    const draftStatus = await getIntentStatus(surreal, intentId);
 82→    expect(draftStatus).toBe("draft");
 83→
 84→    // When the agent submits the intent for authorization
 85→    await submitIntent(surreal, intentId);
 86→
 87→    // Then the intent moves to pending authorization
 88→    const pendingStatus = await getIntentStatus(surreal, intentId);
 89→    expect(pendingStatus).toBe("pending_auth");
 90→
 91→    // When the evaluation pipeline processes the intent
 92→    // (In production, the SurrealQL EVENT fires http::post to the evaluate endpoint.
 93→    //  In tests, we simulate the evaluation result for determinism.)
 94→    await simulateEvaluation(
 95→      surreal,
 96→      intentId,
 97→      {
 98→        decision: "APPROVE",
 99→        risk_score: 15,
100→        reason: "Well-scoped file edit within task boundaries. Low risk.",
101→      },
102→      "authorized",
103→    );
104→
105→    // Then the intent is authorized for execution
106→    const authorizedStatus = await getIntentStatus(surreal, intentId);
107→    expect(authorizedStatus).toBe("authorized");
108→
109→    // And the evaluation result shows low risk with approval
110→    const evaluation = await getIntentEvaluation(surreal, intentId);
111→    expect(evaluation).toBeDefined();
112→    expect(evaluation!.decision).toBe("APPROVE");
113→    expect(evaluation!.risk_score).toBeLessThanOrEqual(30);
114→    expect(evaluation!.reason).toBeTruthy();
115→
116→    // And the intent record preserves the full authorization chain
117→    const record = await getIntentRecord(surreal, intentId);
118→    expect(record.goal).toBe("Add email format validation to the signup form");
119→    expect(record.action_spec.action).toBe("edit_file");
120→    expect(record.trace_id).toBeTruthy();
121→  }, 120_000);
122→
123→  // ---------------------------------------------------------------------------
124→  // Walking Skeleton 2: High-risk intent vetoed by human
125→  // US-1 + US-2 + US-4 + US-5 sad path
126→  // ---------------------------------------------------------------------------
127→  it("agent creates a high-risk intent that a human vetoes before execution", async () => {
128→    const { baseUrl, surreal } = getRuntime();
129→
130→    // Given a workspace with a task that requires a risky operation
131→    const user = await createTestUser(baseUrl, "skeleton-veto");
132→    const workspace = await createTestWorkspace(baseUrl, user);
133→    const task = await createReadyTask(surreal, workspace.workspaceId, {
134→      title: "Migrate database schema for user accounts",
135→      description: "Drop legacy columns and restructure auth tables",
136→    });
137→
138→    // And an agent identity requesting authorization for a destructive action
139→    const agentIdentityId = await createTestIdentity(surreal, "coding-agent", "agent");
140→
141→    // When the agent creates an intent for a destructive database operation
142→    const { intentId } = await createDraftIntent(
143→      surreal,
144→      workspace.workspaceId,
145→      agentIdentityId,
146→      {
147→        goal: "Drop legacy auth columns and restructure user table",
148→        reasoning: "The migration task requires removing deprecated columns. This is a destructive schema change affecting production data.",
149→        priority: 80,
150→        action_spec: {
151→          provider: "database",
152→          action: "execute_migration",
153→          params: { target: "schema/migrations/drop_legacy_auth.surql" },
154→        },
155→        budget_limit: { amount: 50.0, currency: "USD" },
156→        taskId: task.taskId,
157→      },
158→    );
159→
160→    // And the agent submits the intent for authorization
161→    await submitIntent(surreal, intentId);
162→
163→    // When the evaluation pipeline identifies it as high-risk
164→    await simulateEvaluation(
165→      surreal,
166→      intentId,
167→      {
168→        decision: "APPROVE",
169→        risk_score: 75,
170→        reason: "Destructive schema migration. High risk due to irreversible data changes.",
171→      },
172→      "pending_veto",
173→    );
174→
175→    // Then the intent enters the veto window for human review
176→    const vetoStatus = await getIntentStatus(surreal, intentId);
177→    expect(vetoStatus).toBe("pending_veto");
178→
179→    // And the intent appears in the list of intents awaiting human review
180→    const pendingIntents = await listPendingIntents(surreal, workspace.workspaceId);
181→    const found = pendingIntents.find(
182→      (i) => (i.id.id as string) === intentId,
183→    );
184→    expect(found).toBeDefined();
185→    expect(found!.goal).toBe("Drop legacy auth columns and restructure user table");
186→
187→    // And the intent has a veto window expiry set
188→    const record = await getIntentRecord(surreal, intentId);
189→    expect(record.veto_expires_at).toBeDefined();
190→
191→    // When the workspace owner vetoes the intent
192→    // (Direct DB update to simulate veto since the HTTP endpoint is not yet implemented)
193→    const intentRecord = new RecordId("intent", intentId);
194→    await surreal.query(
195→      `UPDATE $intent SET status = "vetoed", veto_reason = $reason, updated_at = time::now();`,
196→      {
197→        intent: intentRecord,
198→        reason: "Too risky without a backup plan. Create a rollback migration first.",
199→      },
200→    );
201→
202→    // Then the intent is vetoed and cannot proceed to execution
203→    const finalStatus = await getIntentStatus(surreal, intentId);
204→    expect(finalStatus).toBe("vetoed");
205→
206→    // And the veto reason is recorded for audit
207→    const vetoedRecord = await getIntentRecord(surreal, intentId);
208→    expect(vetoedRecord.veto_reason).toBe(
209→      "Too risky without a backup plan. Create a rollback migration first.",
210→    );
211→
212→    // And the intent no longer appears in the pending review list
213→    const remainingPending = await listPendingIntents(surreal, workspace.workspaceId);
214→    const stillFound = remainingPending.find(
215→      (i) => (i.id.id as string) === intentId,
216→    );
217→    expect(stillFound).toBeUndefined();
218→  }, 120_000);
219→});
