322→ */
323→export async function waitForIntentStatus(
324→  surreal: Surreal,
325→  intentId: string,
326→  targetStatus: IntentStatus | IntentStatus[],
327→  timeoutMs = 30_000,
328→): Promise<IntentStatus> {
329→  const targets = Array.isArray(targetStatus) ? targetStatus : [targetStatus];
330→  const start = Date.now();
331→
332→  while (Date.now() - start < timeoutMs) {
333→    const current = await getIntentStatus(surreal, intentId);
334→    if (targets.includes(current)) {
335→      return current;
336→    }
337→    await Bun.sleep(250);
338→  }
339→
340→  const finalStatus = await getIntentStatus(surreal, intentId);
341→  throw new Error(
342→    `Intent ${intentId} did not reach ${targets.join("|")} within ${timeoutMs}ms. ` +
343→    `Current status: ${finalStatus}`,
344→  );
345→}
