351→ */
352→export async function simulateEvaluation(
353→  surreal: Surreal,
354→  intentId: string,
355→  evaluation: {
356→    decision: "APPROVE" | "REJECT";
357→    risk_score: number;
358→    reason: string;
359→    policy_only?: boolean;
360→  },
361→  resultStatus: IntentStatus,
362→): Promise<void> {
363→  const intentRecord = new RecordId("intent", intentId);
364→  const evalContent = {
365→    decision: evaluation.decision,
366→    risk_score: evaluation.risk_score,
367→    reason: evaluation.reason,
368→    evaluated_at: new Date().toISOString(),
369→    policy_only: evaluation.policy_only ?? false,
370→  };
371→
372→  const updates: Record<string, unknown> = {
373→    status: resultStatus,
374→    evaluation: evalContent,
375→    updated_at: new Date(),
376→  };
377→
378→  // If entering veto window, set expiry
379→  if (resultStatus === "pending_veto") {
380→    const expiresAt = new Date(Date.now() + 5 * 60 * 1000); // 5 min default
381→    updates.veto_expires_at = expiresAt;
382→  }
383→
384→  await surreal.query(`UPDATE $intent MERGE $updates;`, {
385→    intent: intentRecord,
386→    updates,
387→  });
388→}
389→
390→/**
391→ * Queries the identity record for a user to get the identity ID.
392→ * Needed because intent.requester links to identity, not user.
393→ */
394→export async function getIdentityId(
395→  surreal: Surreal,
396→): Promise<string> {
397→  const rows = (await surreal.query(
398→    `SELECT id FROM identity LIMIT 1;`,
399→  )) as Array<Array<{ id: RecordId<"identity"> }>>;
400→  const result = rows[0]?.[0];
401→  if (!result) {
402→    throw new Error("No identity found -- create a test user first");
403→  }
404→  return result.id.id as string;
405→}
406→
407→/**
408→ * Creates a test identity directly in the database.
409→ * Used when we need an identity record without going through auth.
410→ */
411→export async function createTestIdentity(
412→  surreal: Surreal,
413→  name: string,
414→  type: "human" | "agent" = "agent",
415→): Promise<string> {
416→  const identityId = `id-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
417→  const identityRecord = new RecordId("identity", identityId);
418→  await surreal.query(`CREATE $identity CONTENT $content;`, {
419→    identity: identityRecord,
420→    content: {
421→      name,
422→      type,
423→      created_at: new Date(),
424→    },
425→  });
426→  return identityId;
427→}
